// ============================================
// MAILGUN → SMARTEROS EVENT SCHEMA v1
// ============================================

const input = $input.item.json;
const timestamp = new Date().toISOString();

// Extraer datos del payload de Mailgun
const from = input.sender || input.from || '';
const subject = input.subject || 'Sin asunto';
const body = input['body-plain'] || input.body || '';
const email = input.from || input.sender || '';
const to = input.recipient || input.to || '';

// Detectar intent basado en contenido
let intent = 'general_inquiry';
let estimatedValue = 50000;

const lowerSubject = subject.toLowerCase();
const lowerBody = body.toLowerCase();

// Palabras clave para clasificación
if (lowerSubject.includes('precio') || lowerBody.includes('precio') ||
    lowerSubject.includes('cotiz') || lowerBody.includes('cotiz')) {
  intent = 'pricing_request';
  estimatedValue = 150000;
}
else if (lowerSubject.includes('demo') || lowerBody.includes('demo') ||
         lowerSubject.includes('prueba') || lowerBody.includes('prueba')) {
  intent = 'demo_request';
  estimatedValue = 100000;
}
else if (lowerSubject.includes('empresa') || lowerBody.includes('empresa') ||
         lowerSubject.includes('negocio') || lowerBody.includes('negocio')) {
  intent = 'enterprise_inquiry';
  estimatedValue = 300000;
}
else if (lowerSubject.includes('soporte') || lowerBody.includes('soporte') ||
         lowerSubject.includes('ayuda') || lowerBody.includes('ayuda')) {
  intent = 'support';
  estimatedValue = 0;
}

// Extraer nombre del email
const nameMatch = from.match(/([^<]*)</) || from.match(/(.*)@/);
const name = nameMatch ? nameMatch[1].trim() : from.split('@')[0];

// Determinar territorio basado en dominio
let territory = 'CL-RM';
if (email.includes('.cl')) territory = 'CL-RM';
else if (email.includes('.ar')) territory = 'AR-BA';
else if (email.includes('.mx')) territory = 'MX-CMX';
else if (email.includes('.co')) territory = 'CO-DC';
else territory = 'CL-RM';

// Construir evento normalizado
const event = {
  metadata: {
    source_box_id: 'MAILGUN-001',
    territory: territory,
    protocol: 'MCP-V1',
    correlation_id: `email_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    channel: 'email',
    mailgun_data: {
      to: to,
      subject: subject,
      message_id: input['message-id'] || null
    }
  },
  payload: {
    entity: 'Lead',
    action: 'email_received',
    data: {
      intent: intent,
      customer_id: null,
      message: body,
      phone: null,
      email: email,
      business_name: name,
      product: null,
      subject: subject,
      from_name: name,
      value_estimate: estimatedValue
    }
  },
  trust_score: 0.75,
  timestamp: timestamp,
  lifecycle: 'ingested'
};

return { json: event };

